import{b as n,j as t,k as o}from"./three-114a71c7.js";function i(a){const e={a:"a",em:"em",h2:"h2",hr:"hr",p:"p",span:"span",...a.components};return t(o,{children:[n(e.p,{children:"I've been looking at enterprise AI adoption numbers lately and something doesn't add up."}),`
`,t(e.p,{children:["Spending is up everywhere. Every earnings call has an AI section. And yet: research into enterprise AI adoption finds only 4% of companies report ",n(e.em,{children:"significant"})," returns. 95% of pilots fail before scaling. Only 26% of organizations ship a working product at all."]}),`
`,n(e.p,{children:"The gap between the hype and the ROI has a weird explanation. The companies making money aren't doing what everyone else is building."}),`
`,t(e.h2,{id:"where-the-money-went",children:[n(e.a,{"aria-hidden":"true",tabIndex:"-1",href:"#where-the-money-went",children:n(e.span,{className:"icon icon-link"})}),"Where the money went"]}),`
`,n(e.p,{children:"Organizations put more than half their AI budgets into sales and marketing tools. Makes sense on paper: AI should generate leads, improve conversion, personalize outreach at scale. Revenue is measurable. Easy to justify to a CFO."}),`
`,n(e.p,{children:"The actual ROI data points the other direction. The highest returns came from back-office automation. Invoice processing. Fraud detection. Internal routing and classification. Stuff nobody demos at a conference."}),`
`,t(e.p,{children:["This isn't surprising if you think about it for a minute. Sales and marketing AI operates in an adversarial environment where your competitors are running the same tools, customers are developing immunity to AI-generated content, and success still requires human judgment about timing and relationships. Back-office automation competes against ",n(e.em,{children:"a spreadsheet"}),". If you automate invoice matching at 90% accuracy, you've won, because the human doing it at 85% costs $80k a year and hates the job."]}),`
`,n(e.p,{children:"The companies that got good at AI started with the boring stuff. The companies still failing started with the chatbot."}),`
`,t(e.p,{children:["If your company is in the second group and you're trying to figure out where to actually start, ",n(e.a,{href:"/ai/",children:"this is what I do"}),"."]}),`
`,t(e.h2,{id:"the-data-problem-everyone-misdiagnoses",children:[n(e.a,{"aria-hidden":"true",tabIndex:"-1",href:"#the-data-problem-everyone-misdiagnoses",children:n(e.span,{className:"icon icon-link"})}),"The data problem everyone misdiagnoses"]}),`
`,n(e.p,{children:"80% of AI projects fail before production. Post-mortems almost always say the same thing: data quality."}),`
`,n(e.p,{children:"So companies hire data engineers, buy data governance platforms, start a data quality initiative. And still fail."}),`
`,n(e.p,{children:"The actual issue is bidirectional. AI tools don't adapt to how your organization works. But organizations also don't have frameworks for integrating AI into how they actually work. You can't fix one without the other."}),`
`,t(e.p,{children:["Generic tools fail at enterprise scale not because they're bad tools. It's that enterprise workflows are ",n(e.em,{children:"specific"}),". ChatGPT works great for an individual who can steer it, correct it, and use it opportunistically. It falls apart for an organization that needs consistent, auditable outputs woven into processes designed in 2012."]}),`
`,n(e.p,{children:'Most "AI transformations" are trying to adapt the organization to the tool. The ones that work figured out the specific task first, then found the tool for that task.'}),`
`,t(e.h2,{id:"when-the-ai-works-exactly-as-intended",children:[n(e.a,{"aria-hidden":"true",tabIndex:"-1",href:"#when-the-ai-works-exactly-as-intended",children:n(e.span,{className:"icon icon-link"})}),"When the AI works exactly as intended"]}),`
`,n(e.p,{children:"There's a failure mode that doesn't make it into case studies: agents that function correctly and still cause disasters."}),`
`,n(e.p,{children:`Customer service agents have committed companies to binding contracts. 50% discounts on non-discountable products. Full refunds on non-refundable tickets. The agents weren't hallucinating. They were resolving complaints, which is what they were told to do. They just didn't have the judgment to understand "resolve" has limits.`}),`
`,n(e.p,{children:"Loan decision agents have passed every technical benchmark but couldn't produce fair-lending citations when regulators asked. The system worked. The deployment failed."}),`
`,n(e.p,{children:`This is different from a hallucination problem. The model output was correct for the objective it was given. The objective was wrong. Someone defined "resolve customer complaints" without defining what resolution isn't allowed to look like, and nobody thought about the regulator question until after launch.`}),`
`,t(e.h2,{id:"the-safety-mechanism-problem",children:[n(e.a,{"aria-hidden":"true",tabIndex:"-1",href:"#the-safety-mechanism-problem",children:n(e.span,{className:"icon icon-link"})}),"The safety mechanism problem"]}),`
`,n(e.p,{children:"Organizations building agentic systems quickly learned that humans need to be in the loop. Every action gets approved before execution. Reasonable."}),`
`,n(e.p,{children:"Then users started getting hundreds of approval requests per day. Sometimes thousands. They clicked through without reading. Eventually some organizations enabled auto-approve modes because the constant interruptions were destroying productivity."}),`
`,n(e.p,{children:"The human review layer became the vulnerability. Not because attackers exploited it, but because humans adapted to being constantly interrupted by making the interruptions stop. Normal behavior. Completely predictable. Apparently not anticipated."}),`
`,t(e.h2,{id:"whats-actually-working",children:[n(e.a,{"aria-hidden":"true",tabIndex:"-1",href:"#whats-actually-working",children:n(e.span,{className:"icon icon-link"})}),"What's actually working"]}),`
`,n(e.p,{children:"Fraud detection keeps coming up as a real success. The pattern: one agent flags anomalies, a second checks compliance, a third writes the summary. A human makes the final call. AI handles the parts that require processing thousands of data points in milliseconds; the human handles the judgment."}),`
`,n(e.p,{children:"It works because the task is narrow and well-defined. Failure modes are understood in advance. The human role is real, not performative. Success is measurable: fraud got caught or it didn't."}),`
`,n(e.p,{children:"That pattern doesn't map to every use case. But it explains why back-office numbers are better. Narrow, specific, auditable tasks where the cost of doing it wrong is known and the definition of done is unambiguous."}),`
`,n(e.hr,{}),`
`,n(e.p,{children:"Sources: MIT Sloan research on enterprise AI adoption · International AI Safety Report 2026 (Yoshua Bengio, 100+ researchers)"})]})}function s(a={}){const{wrapper:e}=a.components||{};return e?n(e,{...a,children:n(i,{...a})}):i(a)}export{s as default};
